import scala.collection.mutable.ArrayBuffer

object Solution {
  def matrix(matrix: Array[Array[Long]]): Array[Long] = {
    if (matrix.isEmpty) {
      return Array.empty[Long]
    }

    val n = matrix.length
    val degrees = new Array[Long](n)

    for (i <- 0 until n) {
      var degree = 0L
      for (j <- 0 until n) {
        // Since matrix[i][i] is guaranteed to be 0, we just sum up the row.
        // Because the graph is undirected (matrix[i][j] == matrix[j][i]) and
        // self-loops are excluded, summing the i-th row gives the degree of vertex i.
        if (matrix(i)(j) == 1L) {
          degree += 1L
        }
      }
      degrees(i) = degree
    }

    degrees
  }
}
